import{_ as e,o as r,c as s,ag as o}from"./chunks/framework.6ZJjlmu_.js";const g=JSON.parse('{"title":"Subscriber growth alerts","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/subscriber-growth-alerts.md","filePath":"how-to/subscriber-growth-alerts.md"}'),a={name:"how-to/subscriber-growth-alerts.md"};function n(i,t,d,l,h,c){return r(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="subscriber-growth-alerts" tabindex="-1">Subscriber growth alerts <a class="header-anchor" href="#subscriber-growth-alerts" aria-label="Permalink to &quot;Subscriber growth alerts&quot;">​</a></h1><p>Warns when an event&#39;s subscriber count keeps growing beyond a threshold — similar to Node.js <code>MaxListenersExceededWarning</code>. Helps spot missing <code>-=</code> in <code>OnDestroy</code> / <code>OnDisable</code>.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>A warning fires when <strong>both</strong> are true:</p><ol><li>Subscriber count for an event bucket (<code>OwnerType::EventName</code>) is <strong>above the threshold</strong> (default <strong>10</strong>)</li><li>Count <strong>increased</strong> on each of the last <strong>N</strong> consecutive subscribes (default <strong>3</strong> — reduces false positives from scene-load spikes)</li></ol><p>Unsubscribes that drop count below the threshold <strong>re-arm</strong> the warning for that event.</p><h2 id="where-to-find-them" tabindex="-1">Where to find them <a class="header-anchor" href="#where-to-find-them" aria-label="Permalink to &quot;Where to find them&quot;">​</a></h2><ul><li><strong>Growth Alerts</strong> tab — settings + recent warnings list</li><li>Unity Console — <code>[EventMonitor] Subscriber growth alert: …</code> (when enabled)</li><li><strong>Stats</strong> tab title may include alert count alongside leak count</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>On the <strong>Growth Alerts</strong> tab (persisted via EditorPrefs):</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Meaning</th></tr></thead><tbody><tr><td>Warnings enabled</td><td>ON</td><td>Master switch</td></tr><tr><td>Threshold</td><td>10</td><td>Subscriber count that must be exceeded</td></tr><tr><td>Min growth streak</td><td>3</td><td>Consecutive growth subscribes before warning</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Legitimate fan-out (e.g. UI pooling many listeners) may trigger alerts — raise threshold or disable warnings for that project phase</li><li>Pair with <strong>Leak detection</strong> (Stats tab) for destroyed-object leaks vs runaway growth</li></ul>',13)])])}const u=e(a,[["render",n]]);export{g as __pageData,u as default};
